solutions.javascript:
// Solution
function maxSubarraySum(arr) {
	let maxSum = -Infinity;
	let currentSum = 0;
	for (let num of arr) {
		currentSum = Math.max(num, currentSum + num);
		maxSum = Math.max(maxSum, currentSum);
	}
	return maxSum;
}
